def validate(args, output):
    s = args[0]
    if not isinstance(output, str) or len(output) != len(s):
        return False
    for i in range(len(s)):
        c = output[i]
        if c < 'a' or c > 'z':
            return False
        if s[i] != '?' and c != s[i]:
            return False
    for i in range(len(output) - 1):
        if output[i] == output[i + 1]:
            return False
    return True

