    for (let i = 0; i < s.length; i++) {
        const c = output[i];
        if (c < 'a' || c > 'z') return false;
        if (s[i] !== '?' && c !== s[i]) return false;
    }
    for (let i = 0; i < output.length - 1; i++) {
        if (output[i] === output[i + 1]) return false;
    }
    return true;
}

