def gen(rng, size):
    n = max(1, min(size, 100))
    result = []
    for _ in range(n):
        if rng.random() < 0.4:
            result.append('?')
        else:
            choices = 'abcdefghijklmnopqrstuvwxyz'
            if result and result[-1] != '?':
                choices = [c for c in choices if c != result[-1]]
            result.append(rng.choice(choices))
    return [''.join(result)]

