class Solution:
    def modifyString(self, s):
        chars = list(s)
        n = len(chars)
        for i in range(n):
            if chars[i] != '?':
                continue
            forbidden = set()
            if i > 0:
                forbidden.add(chars[i - 1])
            if i + 1 < n:
                forbidden.add(s[i + 1])
            for c in ('a', 'b', 'c'):
                if c not in forbidden:
                    chars[i] = c
                    break
        return ''.join(chars)

