class Solution:
    def modifyString(self, s):
        res = list(s)
        n = len(res)
        for i in range(n):
            if res[i] == '?':
                for c in 'abc':
                    if (i == 0 or res[i - 1] != c) and (i == n - 1 or res[i + 1] != c):
                        res[i] = c
                        break
        return ''.join(res)

